#include <stack>

using namespace std;

class Solution
{
public:
    int evaluate(const vector<char>& expression)
    {
        stack<int> s;
        stack<char> ops;

        for (char c : expression)
        {
            if (c >= 48 and c <= 57)
                s.push(c - 48);
            else if (c == '(')
                ops.push(c);
            else if (c == ')')
            {
                while (!ops.top() == '(')
                {
                    char op = ops.top();
                    ops.pop();
                    int operand2 = s.top();
                    s.pop();
                    int operand1 = s.top();
                    s.pop();

                    if (op == '+')
                        s.push(operand1 + operand2);
                    else if (op == '-')
                        s.push(operand1 - operand2);
                    else if (op == '*')
                        s.push(operand1 * operand2);
                    else if (op == '/')
                        s.push(operand1 / operand2);
                }
                ops.pop();
            } else
                ops.push(c);
        }

        while (!ops.empty())
        {
            char op = ops.top();
            ops.pop();
            int operand2 = s.top();
            s.pop();
            int operand1 = s.top();
            s.pop();

            if (op == '+')
                s.push(operand1 + operand2);
            else if (op == '-')
                s.push(operand1 - operand2);
            else if (op == '*')
                s.push(operand1 * operand2);
            else if (op == '/')
                s.push(operand1 / operand2);
        }
        return s.top();
    }
};

